
'use client';

import { useState, useEffect } from 'react';
import { Eye, Download, Package } from 'lucide-react';
import { useAuth } from '@/lib/auth';
import { getOrdersByCustomer, Order } from '@/lib/db';

export default function OrdersSection() {
  const { user } = useAuth();
  const [orders, setOrders] = useState<Order[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [selectedOrder, setSelectedOrder] = useState<Order | null>(null);

  useEffect(() => {
    if (user) {
      loadOrders();
    }
  }, [user]);

  const loadOrders = async () => {
    if (!user) return;

    try {
      setLoading(true);
      setError(null);
      
      const { data, error: fetchError } = await getOrdersByCustomer(user.id);

      if (fetchError) {
        throw new Error(fetchError);
      }

      setOrders(Array.isArray(data) ? data : []);
    } catch (err: any) {
      console.error('Error loading orders:', err);
      setError(err.message || 'Errore nel caricamento degli ordini');
      setOrders([]);
    } finally {
      setLoading(false);
    }
  };

  const getStatusColor = (status: string) => {
    const colors: Record<string, string> = {
      ricevuto: 'bg-gray-100 text-gray-800',
      pagato: 'bg-blue-100 text-blue-800',
      in_lavorazione: 'bg-yellow-100 text-yellow-800',
      spedito: 'bg-purple-100 text-purple-800',
      consegnato: 'bg-green-100 text-green-800',
      annullato: 'bg-red-100 text-red-800',
      rimborsato: 'bg-pink-100 text-pink-800',
    };
    return colors[status] || 'bg-gray-100 text-gray-800';
  };

  const getStatusLabel = (status: string) => {
    const labels: Record<string, string> = {
      ricevuto: 'Ricevuto',
      pagato: 'Pagato',
      in_lavorazione: 'In Lavorazione',
      spedito: 'Spedito',
      consegnato: 'Consegnato',
      annullato: 'Annullato',
      rimborsato: 'Rimborsato',
    };
    return labels[status] || status;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <div className="text-center">
          <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary mx-auto mb-4"></div>
          <p className="text-gray-500">Caricamento ordini...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="bg-red-50 border border-red-200 rounded-lg p-6 text-center">
        <p className="text-red-600 font-medium mb-2">Errore</p>
        <p className="text-red-500 text-sm mb-4">{error}</p>
        <button
          onClick={loadOrders}
          className="px-4 py-2 bg-red-600 text-white rounded hover:bg-red-700"
        >
          Riprova
        </button>
      </div>
    );
  }

  if (orders.length === 0) {
    return (
      <div className="text-center py-12">
        <Package className="w-16 h-16 text-gray-300 mx-auto mb-4" />
        <h3 className="text-lg font-medium text-gray-900 mb-2">
          Nessun ordine
        </h3>
        <p className="text-gray-500 mb-6">
          Non hai ancora effettuato ordini
        </p>
        <a
          href="/catalogo"
          className="inline-block px-6 py-3 bg-primary text-white rounded-lg hover:bg-secondary"
        >
          Inizia a comprare
        </a>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h2 className="text-2xl font-bold">I Miei Ordini</h2>
        <p className="text-sm text-gray-500">
          {orders.length} {orders.length === 1 ? 'ordine' : 'ordini'}
        </p>
      </div>

      <div className="space-y-4">
        {orders.map((order) => (
          <div
            key={order.id}
            className="border rounded-lg p-4 hover:shadow-md transition-shadow"
          >
            <div className="flex justify-between items-start mb-3">
              <div>
                <h3 className="font-bold text-lg">{order.numero}</h3>
                <p className="text-sm text-gray-500">
                  {new Date(order.created_at).toLocaleDateString('it-IT', {
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                  })}
                </p>
              </div>
              <span
                className={`px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(
                  order.stato
                )}`}
              >
                {getStatusLabel(order.stato)}
              </span>
            </div>

            <div className="mb-3">
              <p className="text-sm text-gray-600 mb-1">
                {order.righe?.length || 0}{' '}
                {order.righe?.length === 1 ? 'prodotto' : 'prodotti'}
              </p>
              {order.righe && order.righe.length > 0 && (
                <div className="text-sm text-gray-500">
                  {order.righe.slice(0, 2).map((riga) => (
                    <div key={riga.id}>• {riga.prodotto_nome}</div>
                  ))}
                  {order.righe.length > 2 && (
                    <div className="text-xs text-gray-400 mt-1">
                      + altri {order.righe.length - 2} prodotti
                    </div>
                  )}
                </div>
              )}
            </div>

            <div className="flex justify-between items-center pt-3 border-t">
              <p className="text-2xl font-bold text-primary">
                €{order.totale.toFixed(2)}
              </p>
              <div className="flex space-x-2">
                <button
                  onClick={() => setSelectedOrder(order)}
                  className="flex items-center space-x-1 px-3 py-2 bg-gray-100 hover:bg-gray-200 rounded"
                >
                  <Eye className="w-4 h-4" />
                  <span className="text-sm">Dettagli</span>
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>

      {selectedOrder && (
        <div className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4">
          <div className="bg-white rounded-lg max-w-2xl w-full max-h-[90vh] overflow-y-auto">
            <div className="sticky top-0 bg-white border-b p-4 flex justify-between items-center">
              <h3 className="text-xl font-bold">
                Ordine {selectedOrder.numero}
              </h3>
              <button
                onClick={() => setSelectedOrder(null)}
                className="text-gray-500 hover:text-gray-700 text-2xl"
              >
                ×
              </button>
            </div>

            <div className="p-6 space-y-6">
              <div>
                <h4 className="font-semibold mb-2">Stato</h4>
                <span
                  className={`inline-block px-3 py-1 rounded-full text-sm font-medium ${getStatusColor(
                    selectedOrder.stato
                  )}`}
                >
                  {getStatusLabel(selectedOrder.stato)}
                </span>
              </div>

              <div>
                <h4 className="font-semibold mb-2">Prodotti</h4>
                <div className="space-y-2">
                  {selectedOrder.righe?.map((riga) => (
                    <div
                      key={riga.id}
                      className="flex justify-between items-center py-2 border-b"
                    >
                      <div className="flex-1">
                        <p className="font-medium">{riga.prodotto_nome}</p>
                        <p className="text-sm text-gray-500">
                          SKU: {riga.prodotto_sku}
                        </p>
                        <p className="text-xs text-gray-400">
                          Qtà: {riga.quantita} × €{riga.prezzo_unitario.toFixed(2)}
                        </p>
                      </div>
                      <p className="font-semibold">
                        €{riga.totale_riga.toFixed(2)}
                      </p>
                    </div>
                  ))}
                </div>
              </div>

              <div className="border-t pt-4">
                <div className="flex justify-between mb-2">
                  <span>Subtotale</span>
                  <span>€{selectedOrder.subtotale.toFixed(2)}</span>
                </div>
                {selectedOrder.sconto_totale > 0 && (
                  <div className="flex justify-between mb-2 text-green-600">
                    <span>Sconto</span>
                    <span>-€{selectedOrder.sconto_totale.toFixed(2)}</span>
                  </div>
                )}
                <div className="flex justify-between mb-2">
                  <span>Spedizione</span>
                  <span>
                    {selectedOrder.costo_spedizione === 0
                      ? 'Gratis'
                      : `€${selectedOrder.costo_spedizione.toFixed(2)}`}
                  </span>
                </div>
                <div className="flex justify-between text-xl font-bold pt-2 border-t">
                  <span>Totale</span>
                  <span>€{selectedOrder.totale.toFixed(2)}</span>
                </div>
              </div>

              {selectedOrder.indirizzo_spedizione && (
                <div>
                  <h4 className="font-semibold mb-2">Indirizzo di Spedizione</h4>
                  <div className="bg-gray-50 p-3 rounded text-sm">
                    <p>
                      {selectedOrder.indirizzo_spedizione.nome}{' '}
                      {selectedOrder.indirizzo_spedizione.cognome}
                    </p>
                    <p>{selectedOrder.indirizzo_spedizione.via}</p>
                    <p>
                      {selectedOrder.indirizzo_spedizione.cap}{' '}
                      {selectedOrder.indirizzo_spedizione.citta}
                    </p>
                    {selectedOrder.indirizzo_spedizione.telefono && (
                      <p>Tel: {selectedOrder.indirizzo_spedizione.telefono}</p>
                    )}
                  </div>
                </div>
              )}

              {selectedOrder.tracking_code && (
                <div>
                  <h4 className="font-semibold mb-2">Tracking Spedizione</h4>
                  <p className="font-mono text-sm bg-gray-50 p-3 rounded">
                    {selectedOrder.tracking_code}
                  </p>
                  {selectedOrder.metodo_spedizione && (
                    <p className="text-sm text-gray-500 mt-1">
                      Metodo: {selectedOrder.metodo_spedizione}
                    </p>
                  )}
                </div>
              )}
            </div>

            <div className="sticky bottom-0 bg-white border-t p-4 flex justify-end">
              <button
                onClick={() => setSelectedOrder(null)}
                className="px-6 py-2 bg-gray-200 hover:bg-gray-300 rounded"
              >
                Chiudi
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}